def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 2.0:
            priority = (ratio - 2.0) ** 3 * 350
            if capacity % 2 == 0:
                priority += 5 * ((capacity // 2) % 3)
            for a in range(1, 5):
                priority += np.tanh(ratio * a) * a * 3
            if ratio > 4.0:
                priority += (ratio - 4.0) ** 2 * 120
                for b in range(1, 3):
                    priority -= np.exp(-b * ratio) * 15 * b
            if capacity > 10 * item:
                priority -= 25
        elif 1.0 < ratio <= 2.0:
            priority = (2.0 - ratio) ** 1.7 * 280 + 15
            if capacity % 5 == 0:
                priority += 4.2
            elif capacity % 3 == 0:
                priority += 3.3
            else:
                priority += 1.1
            for c in range(2, 7):
                factor = (-1) ** c * np.sin(ratio * c * np.pi / 2) / (c * 0.6)
                priority += factor * (c ** 1.2)
        else:
            acc = 0
            for d in range(1, 12):
                term = ((-1) ** (d + 1)) * (ratio ** (d * 1.3)) / (d + 0.5)
                if d % 4 == 0:
                    term *= 2.0
                acc += term
            priority += abs(acc) * 2.1
            if capacity < item * 1.5:
                priority *= 3.3
            diff = np.log(capacity + 3) - np.log(item + 2)
            if diff > 0:
                priority += 12 / diff
            else:
                priority += 40
            mods = [capacity % 2, capacity % 3, capacity % 5, capacity % 7, capacity % 11]
            priorities_map = {0: 1.8, 1: 1.5, 2: 1.2, 3: 0.9, 4: 0.7}
            for idx, mod in enumerate(mods):
                if mod == 0:
                    priority += priorities_map.get(idx, 0.3)
                    break
            if ratio < 0.35:
                for e in range(1, 7):
                    scale = e * 0.85
                    val = ((-1) ** (e + 1)) * (ratio ** (e * 2.2)) * scale
                    if e == 5 and capacity > item * 8:
                        val *= 1.5
                    priority += val
            if capacity > 5 * item:
                priority -= 3.7
            if capacity % 9 == 0 and ratio < 0.6:
                priority -= 1.3
            if capacity > item * 10:
                for f in range(2, 8):
                    sqrt_f = np.sqrt(f)
                    power_term = ratio ** (1 / f)
                    sign_term = (-1) ** (f + 1)
                    priority += sqrt_f * power_term * sign_term * (f * 0.4)
            if priority > 65:
                priority = 65 + np.log(priority - 64) * 1.7
            if priority < 0:
                priority = 0
        priorities[i] = priority
    return priorities
